optimized_federated_query:
# Smart Federated Query with Class Constraints
# Note: Multiple class interpretations exist but all route to same endpoints
# A single query retrieves all data regardless of class ambiguity

SELECT ?Drug ?Int ?IntDrug ?IntEffect ?y
WHERE {

  SERVICE <http://localhost:8892/sparql/> {
    ?Int <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/interactionDrug1> ?y . # ?Int:drug_interactions, ?y:Offer
    ?Int <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/interactionDrug2> ?IntDrug . # ?Int:drug_interactions, ?IntDrug:drugs
    ?Int <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/text> ?IntEffect . # ?Int:drug_interactions, ?IntEffect:Literal
  }

  SERVICE <http://localhost:8897/sparql/> {
    ?y <http://www.w3.org/2002/07/owl#sameAs> ?Drug . # ?y:Concept, ?Drug:Feature
    ?Drug <http://www.w3.org/1999/02/22-rdf-syntax-ns#type> <http://dbpedia.org/ontology/Drug> .
  }
}
LIMIT 1000
